mapper.select:
        SELECT
        
        
        ,homework.homework_name as homeworkName
        ,homework.homework_myscore as homeworkMyscore

        ,homework.homework_types as homeworkTypes
        ,homework.zujuan_types as zujuanTypes
        ,homework.homework_delete as homeworkDelete
        ,examquestion.examquestion_name as examquestionName

        ,examquestion.examquestion_options as examquestionOptions
        ,examquestion.examquestion_answer as examquestionAnswer
        ,examquestion.examquestion_analysis as examquestionAnalysis
        ,examquestion.examquestion_types as examquestionTypes
        ,examquestion.examquestion_sequence as examquestionSequence

        FROM homeworktopic  a
        left JOIN homework homework ON a.homework_id = homework.id
        left JOIN examquestion examquestion ON a.examquestion_id = examquestion.id

        
            
                and a.id in
                
                #{item}
                
            
            
                and (
                    a.homework_id = #{params.homeworkId}
                )
            
            
                and (
                    a.examquestion_id = #{params.examquestionId}
                )
            
            
                  and a.homeworktopic_number >= #{params.homeworktopicNumberStart}   
            
            
                  and a.homeworktopic_number <= #{params.homeworktopicNumberEnd}   
            
             
                and a.homeworktopic_number = #{params.homeworktopicNumber}
             

                
            
                and a.homework_id IS NOT NULL
            
            
                and homework.homework_name like CONCAT('%',#{params.homeworkName},'%')
            
            
                  and homework.homework_myscore >= #{params.homeworkMyscoreStart}   
            
            
                  and homework.homework_myscore <= #{params.homeworkMyscoreEnd}   
            
            
                and homework.homework_myscore = #{params.homeworkMyscore}
            


            
                and homework.homework_types = #{params.homeworkTypes}
            

            
                and homework.zujuan_types = #{params.zujuanTypes}
            

            
                  and homework.homework_delete >= #{params.homeworkDeleteStart}   
            
            
                  and homework.homework_delete <= #{params.homeworkDeleteEnd}   
            
            
                and homework.homework_delete = #{params.homeworkDelete}
            
                
            
                and a.examquestion_id IS NOT NULL
            
            
                and examquestion.examquestion_name like CONCAT('%',#{params.examquestionName},'%')
            


            
                and examquestion.examquestion_options like CONCAT('%',#{params.examquestionOptions},'%')
            
            
                and examquestion.examquestion_answer like CONCAT('%',#{params.examquestionAnswer},'%')
            
            
                and examquestion.examquestion_analysis like CONCAT('%',#{params.examquestionAnalysis},'%')
            
            
                and examquestion.examquestion_types = #{params.examquestionTypes}
            

            
                  and examquestion.examquestion_sequence >= #{params.examquestionSequenceStart}   
            
            
                  and examquestion.examquestion_sequence <= #{params.examquestionSequenceEnd}   
            
            
                and examquestion.examquestion_sequence = #{params.examquestionSequence}
            
        
        order by a.${params.sort} ${params.order}
